import type {ArticleSection} from '../types/philosophy';

const section=(id:string,title:string,paragraphs:string[],relatedBranchIds?:string[],relatedPhilosopherIds?:string[],relatedWorkTitles?:string[]):ArticleSection=>({id,title,paragraphs,relatedBranchIds,relatedPhilosopherIds,relatedWorkTitles});

export const medievalIslamicContinuationPhilosopherArticles:Record<string,ArticleSection[]>={
  'al-kindi':[
    section('overview','The first philosopher of the Arabic tradition',[
      'Al-Kindi is often called the first philosopher of the Arabs, not because no one before him asked speculative questions in Arabic, but because he helped make Greek philosophical inquiry speak in the language, institutions, and problems of the early Abbasid world. His project joined translation, mathematics, medicine, optics, music, metaphysics, and theology into a program of rational cultivation. He did not inherit philosophy as a settled school with Arabic textbooks ready for use. He worked at the moment when philosophical vocabulary itself had to be chosen, adapted, and defended.',
      'His importance is therefore both doctrinal and infrastructural. Al-Kindi argues about God, soul, intellect, causality, and the value of philosophy, but he also helps create the conditions under which later thinkers such as al-Farabi, Avicenna, al-Ghazali, Averroes, Maimonides, and Aquinas could argue with Greek and Arabic materials together. He is best read as a founding mediator: someone who receives Aristotle, late antique Platonism, mathematical sciences, and Islamic monotheism while trying to show that the search for truth is not a foreign intrusion but a disciplined form of gratitude for reality.'
    ],['islamic-philosophy','metaphysics','philosophy-of-religion'],['al-kindi','aristotle','plato','al-farabi'],['On First Philosophy']),
    section('abbasid-context','The Abbasid setting and the translation movement',[
      'Al-Kindi lived in the ninth-century Abbasid world, especially in Baghdad, where court patronage, scholarly competition, and translation activity made Greek, Syriac, Persian, Indian, and Arabic learning newly available in concentrated forms. The translation movement was not a neutral conveyor belt. Translators and patrons selected texts, coined technical terms, summarized difficult arguments, and sometimes transmitted works through late antique paraphrase rather than direct Greek originals. Philosophy entered Arabic through a complicated workshop of languages and institutions.',
      'This setting explains why al-Kindi sometimes sounds like an Aristotelian, sometimes like a Platonist, and sometimes like a theologian using philosophical tools. The borders were not yet neat. Texts associated with Aristotle might carry Neoplatonic ideas; mathematical sciences could be treated as training for metaphysics; courtly service could support speculative inquiry while also exposing it to political danger. Al-Kindi belongs to this experimental moment. He is not merely importing ancient thought. He is helping decide what "philosophy" can mean inside an Islamic imperial culture.'
    ],['islamic-philosophy','aristotelianism'],['al-kindi','aristotle'],[]),
    section('philosophy-defense','Why philosophy needed a defense',[
      'Al-Kindi repeatedly presents philosophy as the search for truth about things according to human capacity. That formulation matters because philosophy could be suspected of foreignness, arrogance, or useless subtlety. He answers by arguing that truth should be accepted from wherever it comes, even from peoples distant in language or religion. This is not a modern slogan of neutral cosmopolitanism. It is a defense of intellectual humility: no community owns truth so completely that it can refuse help from earlier seekers.',
      'The defense also has a moral edge. If truth is valuable, then gratitude requires receiving and improving what previous thinkers discovered. Al-Kindi asks his readers to treat Greek learning neither as sacred authority nor as contamination, but as material to be examined. That posture anticipates a recurring theme in Islamic philosophy: rational inquiry must justify its place without pretending to stand outside revelation, language, politics, or inherited education. Philosophy becomes an act of disciplined reception.'
    ],['islamic-philosophy','epistemology'],['al-kindi','aristotle'],['On First Philosophy']),
    section('metaphysics-god','First philosophy, creation, and divine unity',[
      'In On First Philosophy, al-Kindi treats metaphysics as inquiry into the first cause and the deepest structure of being. He argues that the world is dependent and finite, and that the ultimate cause must be one, simple, and unlike the things it causes. His account draws on Aristotelian and Neoplatonic materials, but it is shaped by a strong monotheistic concern: God is not one item inside the universe, not a body, not composed of parts, and not subject to the divisions found in created things.',
      'The relation between philosophy and creation is delicate. Aristotle was often associated with an eternal cosmos, while Islamic doctrine affirmed created dependence on God. Al-Kindi presses arguments for finitude and creation, seeking a philosophical route that supports divine origination without reducing God to a craftsman working on preexisting matter. Later Islamic philosophers would handle this problem differently, especially Avicenna with necessity and emanation and Averroes with a more Aristotelian defense. Al-Kindi marks an early attempt to make metaphysics answerable to divine unity and creation together.'
    ],['metaphysics','philosophy-of-religion','islamic-philosophy'],['al-kindi','aristotle','avicenna','averroes'],['On First Philosophy']),
    section('negative-language','Divine simplicity and the limits of language',[
      'Al-Kindi insists that God cannot be described in the same way created things are described. If ordinary predicates divide a subject into qualities, kinds, or parts, they cannot apply straightforwardly to the absolutely one source of all things. This pushes his theology toward disciplined negation. God is known as cause and as one, but not by placing God under the categories that classify creatures. Such language protects transcendence from being turned into an enlarged image of the world.',
      'This theme links al-Kindi to later negative theology while also showing his own early philosophical caution. The point is not that nothing can be said about God. Rather, speech about God must be purified of the assumption that divine unity is just another example of numerical unity. The difficulty remains: if language is so limited, how can metaphysics teach anything positive? Al-Kindi answers through causality, unity, and removal of false likeness, leaving later thinkers to refine the balance between meaningful naming and transcendence.'
    ],['philosophy-of-religion','metaphysics'],['al-kindi','maimonides','aquinas'],['On First Philosophy']),
    section('soul-intellect','Soul, intellect, and the ascent of understanding',[
      'Al-Kindi wrote on the soul and the intellect in a setting where Aristotle, Plato, and late antique commentators were often read together. The soul is not treated merely as a religious object of belief. It is the principle of life, perception, desire, and intellectual activity, and it raises questions about what kind of being can know universal truths. His short treatise On the Intellect helped transmit distinctions about actual, potential, and acquired intellect that became central to Arabic and Latin debates.',
      'The importance of these discussions is easy to miss because later theories by al-Farabi, Avicenna, and Averroes are more elaborate. Al-Kindi is working at an earlier stage, trying to make the vocabulary of intellect usable. The question is not only how an individual person thinks, but how human understanding relates to immaterial intelligibles and to a cosmic order. In his hands, psychology becomes a bridge between ethics, epistemology, and metaphysics: to know truly is to be reordered toward what is higher than bodily appetite or social ambition.'
    ],['epistemology','metaphysics','islamic-philosophy'],['al-kindi','al-farabi','avicenna','averroes'],['On the Intellect']),
    section('mathematics-science','Mathematics, music, optics, and the scientific temperament',[
      'Al-Kindi was not only a metaphysician. He wrote on mathematics, astronomy, astrology, medicine, optics, music, and the classification of the sciences. This range reflects the ancient and late antique conviction that philosophical education includes mathematical discipline. Number, proportion, and measurement train the mind to see order more exactly than ordinary perception allows. Music, for example, is not only entertainment; it can reveal mathematical harmony and the relation between bodily experience and intelligible structure.',
      'Modern readers sometimes separate "science" from "philosophy" so sharply that al-Kindi looks scattered. In his world, the sciences formed a hierarchy of disciplined approaches to reality. Optics studies how sight works; medicine studies the body; mathematics studies abstract order; metaphysics asks about first causes. The danger, especially in areas such as astrology, is that inherited sciences may carry assumptions later judged unreliable. The historical lesson is not that every claim succeeds, but that al-Kindi models a philosophical culture in which mathematics and natural inquiry matter for understanding the whole.'
    ],['islamic-philosophy','epistemology'],['al-kindi'],[]),
    section('ethics-therapy','Ethics as therapy for grief and attachment',[
      'Al-Kindi\'s work on dispelling sorrows shows a practical side of his philosophy. Human beings suffer partly because they attach happiness to perishable things: possessions, status, bodily pleasures, political favor, and relationships vulnerable to loss. Philosophical therapy trains the soul to measure goods differently. This is not a denial that loss hurts. It is an attempt to prevent the self from being ruled by what cannot be secured.',
      'The therapy has affinities with Stoic and Platonic moral traditions, but it is not simply copied from them. Al-Kindi writes in an Islamic ethical horizon where the created world is good yet not ultimate. The task is to love finite goods without mistaking them for final happiness. That remains a demanding balance. If taken crudely, it can sound cold toward grief; if read carefully, it asks how reason can help desire survive a world where every earthly possession can be taken away.'
    ],['islamic-philosophy','philosophy-of-religion'],['al-kindi'],['On Dispelling Sorrows']),
    section('relation-greeks','Relation to Aristotle, Plato, and late antique Platonism',[
      'Al-Kindi revered Greek philosophy, especially Aristotle, but the Aristotle he received was mediated through translations, summaries, and late antique interpretive traditions. Some works circulating under Aristotelian authority contained Neoplatonic material. This helps explain why al-Kindi can combine Aristotelian concern for causes and demonstration with Platonic themes of immaterial reality, ascent, and divine unity. His "Aristotelianism" is not the later, stricter Aristotelianism associated with Averroes.',
      'That mixed inheritance should not be treated as confusion. It was part of the intellectual environment he helped organize. Early Arabic philosophy had to decide how logical, mathematical, cosmological, and theological materials fit together before the lines of school identity hardened. Al-Kindi\'s achievement lies in making that inheritance philosophically productive. He gives later thinkers a shared archive to refine, criticize, and systematize, even when they reject parts of his synthesis.'
    ],['aristotelianism','islamic-philosophy','metaphysics'],['al-kindi','aristotle','plato','averroes'],['On First Philosophy']),
    section('influence-reception','Influence on later Islamic and Latin philosophy',[
      'Al-Kindi\'s direct authority was eventually overshadowed by al-Farabi and Avicenna, whose systems were more technically developed, and by Averroes, whose commentaries reshaped Aristotle\'s reception. Yet being overshadowed is not the same as being unimportant. Al-Kindi helped establish Arabic philosophical prose, translation patronage, scientific classification, and the legitimacy of engaging Greek sources. Later thinkers could become more systematic partly because the early groundwork had been laid.',
      'His influence also reached Latin readers through works on intellect, optics, astrology, and other sciences. Some transmissions were indirect or fragmentary, and attribution can be difficult, so caution is needed. The broader point is secure: al-Kindi belongs to the chain by which ancient philosophy became medieval philosophy across languages. He stands near the beginning of a tradition that would eventually transform debates about divine attributes, causality, intellect, science, and the relation between reason and revelation.'
    ],['islamic-philosophy','aristotelianism','epistemology'],['al-kindi','al-farabi','avicenna','averroes','aquinas'],['On the Intellect']),
    section('translation-method','Translation as philosophical creation',[
      'Al-Kindi\'s circle reminds readers that translation is not merely substitution of one word for another. Philosophical translation requires decisions about what counts as substance, cause, intellect, nature, soul, and unity. Those decisions can make future arguments possible or difficult. A poorly chosen term may distort a doctrine; a successful term can become so natural that later readers forget it was once an invention. Al-Kindi worked in that creative middle space.',
      'This is why his importance cannot be measured only by surviving treatises. He helped stabilize a learned environment in which Greek sciences could be argued about in Arabic and related to Islamic questions. The process involved summaries, corrections, paraphrases, and new compositions as well as literal translation. A tradition is born not only when texts are copied, but when a community gains the concepts, habits, and confidence to dispute them.'
    ],['islamic-philosophy','epistemology'],['al-kindi','aristotle'],[]),
    section('revelation-and-reason','Revelation, reason, and early Islamic theology',[
      'Al-Kindi\'s philosophical theology developed near debates over divine attributes, creation, freedom, and the status of reason in religious argument. He should not be collapsed into any single theological school, but his work clearly belongs to a culture where rational defense of monotheism mattered. Philosophy offered tools for thinking about unity, causality, and incorporeality, while revelation supplied commitments that shaped which metaphysical options seemed acceptable.',
      'The result is not a simple harmony in which reason and revelation automatically agree. It is a negotiated project. Al-Kindi must show that philosophical inquiry can honor divine transcendence without importing unacceptable pictures of God or the world. Later Islamic philosophers would pursue more independent systems, and theologians would often challenge them. Al-Kindi stands near the beginning of that long argument, where philosophy first had to earn a place in the grammar of Islamic learned life.'
    ],['islamic-philosophy','philosophy-of-religion','metaphysics'],['al-kindi','al-farabi','al-ghazali'],['On First Philosophy']),
    section('tensions-misunderstandings','Interpretive tensions and common misunderstandings',[
      'A common misunderstanding treats al-Kindi as a simple transmitter of Greek thought. That misses how much adaptation was required. He had to defend philosophy in Arabic, shape technical vocabulary, and reconcile inherited materials with strong claims about divine unity and creation. Another misunderstanding treats him as a fully mature Aristotelian philosopher. That category fits later figures better. Al-Kindi belongs to an earlier stage in which Aristotelian, Platonic, mathematical, and theological strands were still being braided into Arabic forms.',
      'The tensions are real. His arguments for creation, divine simplicity, and the value of philosophy do not always fit later standards of precision. His scientific interests include fields modern readers treat with suspicion. Some works are lost or survive in complex transmission. Those limitations should make interpretation careful, not dismissive. Al-Kindi is philosophically important because he shows a tradition in formation, where translation, theology, science, and metaphysics are not yet separated into tidy compartments.'
    ],['islamic-philosophy','metaphysics','philosophy-of-religion'],['al-kindi','al-farabi','averroes'],[]),
    section('reading-strategy','How to read al-Kindi well',[
      'Begin with On First Philosophy to see why metaphysics, divine unity, and the defense of philosophy stand together. Then read On the Intellect as a compact doorway into later debates about knowledge and immaterial understanding. Add On Dispelling Sorrows to avoid reducing al-Kindi to abstract metaphysics. That sequence shows the breadth of his project: first cause, human knowing, and moral therapy are connected by the soul\'s need to recognize what is stable and what is not.',
      'The best reading strategy is historical patience. Do not demand from al-Kindi the systematic architecture of Avicenna or the commentary rigor of Averroes. Ask instead what problems had to be solved for such later projects to become possible. Which Greek concepts needed Arabic expression? Which claims about God could philosophy support? Which sciences trained the mind? Which attachments deform the soul? Al-Kindi\'s answers are sometimes preliminary, but preliminary work can be foundational.'
    ],['islamic-philosophy','metaphysics','epistemology'],['al-kindi','avicenna','averroes'],['On First Philosophy','On the Intellect','On Dispelling Sorrows'])
  ],
  'al-farabi':[
    section('overview','The second teacher and the architecture of philosophy',[
      'Al-Farabi stands between al-Kindi\'s pioneering translation-era philosophy and the later systematic achievements of Avicenna and Averroes. Medieval readers called him the "Second Teacher," with Aristotle as the first, because he did so much to organize logic, political philosophy, metaphysics, music, language, and the classification of the sciences into a teachable philosophical order. He did not merely comment on isolated problems. He asked how a complete philosophical education should be built and what kind of city could sustain it.',
      'His thought is ambitious because it joins technical logic to human happiness. Demonstration, language, religion, political leadership, and imagination all matter because human beings need guidance toward perfection. Al-Farabi receives Plato and Aristotle through late antique and Arabic traditions, but he does not simply harmonize them by assertion. He designs a philosophical world in which Aristotelian logic disciplines knowledge, Platonic political aspiration frames collective life, and religion becomes a symbolic and imaginative presentation of truths that philosophy seeks demonstratively.'
    ],['islamic-philosophy','logic','political-philosophy'],['al-farabi','aristotle','plato','avicenna'],['Enumeration of the Sciences','The Opinions of the People of the Virtuous City']),
    section('context','Baghdad, court culture, and philosophical curriculum',[
      'Al-Farabi lived in the tenth century, after the first great surge of translation had made many Greek works available in Arabic but before the later Avicennian synthesis dominated much of the field. The intellectual world he entered included Aristotelian logic, Platonic political texts, medical and mathematical sciences, grammar, theology, jurisprudence, and courtly patronage. Philosophy had more tools than in al-Kindi\'s time, but those tools needed order.',
      'That setting helps explain his concern with curriculum. The question was not only what doctrines are true, but how students move from language to logic, from logic to demonstration, from natural philosophy to metaphysics, and from individual understanding to political life. Al-Farabi\'s writings often function like maps. They classify sciences, explain methods, rank forms of reasoning, and show how different audiences receive truth. He is a philosopher of intellectual formation as much as a philosopher of particular theses.'
    ],['islamic-philosophy','logic','epistemology'],['al-farabi','al-kindi'],['Enumeration of the Sciences']),
    section('logic-method','Logic as the instrument of disciplined thought',[
      'For al-Farabi, logic is not a narrow technical game. It is the instrument that protects reasoning from confusion, especially when words, grammar, and common opinion pull thought in different directions. He wrote on the Aristotelian logical corpus and helped integrate logic into Arabic philosophical education. Logic clarifies terms, propositions, syllogisms, demonstration, dialectic, rhetoric, and poetics, showing how different kinds of speech produce different kinds of assent.',
      'This broad logical vision matters for religion and politics. Human communities are moved not only by demonstration but also by persuasion, images, stories, and poetic representation. Logic therefore does not remove rhetoric and imagination from philosophy; it ranks and analyzes them. A beginner may need persuasive images, while a trained philosopher seeks demonstrative knowledge. The danger is elitism, but the insight is powerful: public language and philosophical proof do not work the same way, and a society that confuses them will misunderstand both.'
    ],['logic','epistemology','islamic-philosophy'],['al-farabi','aristotle','averroes'],['Book of Demonstration','Enumeration of the Sciences']),
    section('classification-sciences','The classification of the sciences',[
      'Al-Farabi\'s Enumeration of the Sciences is one of the clearest expressions of his architectonic mind. It surveys language, logic, mathematics, natural science, metaphysics, politics, jurisprudence, and theology, explaining their objects and methods. Classification is not mere cataloging. To classify a science is to decide what it studies, what kind of certainty it can reach, how it depends on other disciplines, and what role it plays in human perfection.',
      'The inclusion of jurisprudence and theology alongside philosophical sciences is especially important. Al-Farabi does not pretend that societies are guided only by demonstrative philosophers. Legal and religious disciplines shape communities, train conduct, and express beliefs through authoritative forms. By placing them in relation to philosophy, he creates a framework for comparing ways of knowing without collapsing them into one method. The result is a map of knowledge that is intellectual, pedagogical, and political at once.'
    ],['islamic-philosophy','epistemology','political-philosophy'],['al-farabi'],['Enumeration of the Sciences']),
    section('metaphysics-being','Metaphysics, being, and the order of causes',[
      'Al-Farabi\'s metaphysics explores being, causality, intellect, and the first principle in a way that prepares for Avicenna while remaining distinct from him. He inherits Aristotelian questions about substance, cause, and demonstration, but also receives Neoplatonic structures of emanation and hierarchy. The first cause is utterly prior, and lower levels of reality depend on intellectual principles. The cosmos is intelligible because being is ordered through causes.',
      'His metaphysics cannot be separated from his account of knowledge and politics. Human perfection depends on becoming intellectually related to the order of reality. The philosopher seeks knowledge of causes; the prophet-lawgiver communicates an image of that order to a community; the virtuous city organizes life around ultimate happiness. This means metaphysics is not an abstract appendix. It supplies the objective order that education, religion, and law attempt to imitate at human scale.'
    ],['metaphysics','islamic-philosophy','aristotelianism'],['al-farabi','avicenna','aristotle'],['The Opinions of the People of the Virtuous City']),
    section('intellect-prophecy','Intellect, imagination, and prophecy',[
      'Al-Farabi\'s account of intellect and prophecy is one of his most influential achievements. Human beings possess rational capacities that can be perfected through study, moral discipline, and contact with higher intellectual realities. The active intellect plays a crucial role in making intelligibles available to the human mind. At the highest level, the perfected human being receives truth intellectually and also possesses an imagination strong enough to represent that truth in images, laws, and symbols for others.',
      'This theory allows al-Farabi to explain prophecy philosophically without treating it as mere illusion. The prophet is not simply a poet, and the philosopher is not simply a private contemplative. Prophetic imagination translates intellectual truth into forms a community can live by. The tension is obvious: does this account honor revelation, or does it subordinate religion to philosophy? Later readers disagree. What is clear is that al-Farabi makes imagination politically and epistemically serious. Images can guide a city when demonstration is available only to few.'
    ],['philosophy-of-religion','epistemology','islamic-philosophy'],['al-farabi','avicenna','maimonides'],['The Opinions of the People of the Virtuous City']),
    section('virtuous-city','The virtuous city and political happiness',[
      'The Opinions of the People of the Virtuous City presents political philosophy as an inquiry into the conditions under which human beings can reach true happiness. A city is not merely a security arrangement or economic exchange. It is a cooperative order aimed at a shared end. If its end is wealth, domination, pleasure, honor, or mere survival, the city becomes distorted. If its end is true happiness, its institutions, education, and leadership must point citizens toward intellectual and moral perfection.',
      'Al-Farabi adapts Platonic political themes to an Islamic and Aristotelian intellectual world. The ruler of the virtuous city resembles Plato\'s philosopher-ruler but also resembles a prophet-lawgiver who can communicate truth through religion. Political order therefore depends on knowledge, character, imagination, and persuasive teaching. The model is inspiring and troubling. It asks what politics is for at the highest level, but it also raises hard questions about hierarchy, pluralism, coercion, and the place of citizens who cannot share philosophical understanding.'
    ],['political-philosophy','islamic-philosophy','philosophy-of-religion'],['al-farabi','plato','aristotle'],['The Opinions of the People of the Virtuous City','The Political Regime']),
    section('religion-philosophy','Religion as symbolic presentation of truth',[
      'Al-Farabi treats religion as a set of opinions and actions prescribed for a community by a founder or lawgiver. At its best, religion represents philosophical truths in imaginative and practical forms suited to public life. This does not make religion worthless. Most people do not live by demonstration, and even philosophers are formed within communities before they can philosophize. Religion educates desire, coordinates action, and gives images of the highest things.',
      'The cost of this account is the possibility that philosophy appears superior to religion because it grasps demonstratively what religion represents symbolically. That hierarchy shaped later debates in Islamic, Jewish, and Christian philosophy. Some readers see al-Farabi as reducing revelation to political pedagogy; others see him as explaining how divine truth can be mediated through human capacities. A careful reading should preserve the tension. He is neither a simple secularizer nor a simple apologist. He is asking how truth becomes livable for a city.'
    ],['philosophy-of-religion','political-philosophy','islamic-philosophy'],['al-farabi','maimonides','averroes'],['Book of Religion']),
    section('plato-aristotle','Plato, Aristotle, and the problem of harmony',[
      'Al-Farabi is famous for trying to present Plato and Aristotle as fundamentally harmonious, especially when properly understood. This harmonizing project belongs to a late antique inheritance in which the two authorities were often placed within one curriculum. Aristotle supplies logic, scientific method, and analysis of causes; Plato supplies powerful models of political order, ascent, and the relation between philosophy and public life. Al-Farabi uses both because his project needs both.',
      'Modern scholars may doubt that Plato and Aristotle are as harmonious as al-Farabi suggests. That doubt is useful, but it should not make the project look naive. Harmonization was a philosophical strategy for building a unified curriculum and defending the coherence of inherited wisdom. The question is not only whether Plato and Aristotle agreed historically. It is how a tradition can organize multiple authorities without fragmenting. Al-Farabi\'s answer shaped centuries of philosophical education, even where later thinkers identified sharper disagreements.'
    ],['aristotelianism','political-philosophy','islamic-philosophy'],['al-farabi','plato','aristotle','averroes'],['The Philosophy of Plato and Aristotle']),
    section('music-language','Music, language, and embodied education',[
      'Al-Farabi wrote a major work on music, showing that his interest in order extended beyond abstract logic. Music involves proportion, perception, habit, emotional training, and mathematical structure. It reveals how the soul can be moved through patterns that are not simply demonstrative arguments. This matters for political philosophy because communities are educated through sounds, stories, images, and rituals as well as through propositions.',
      'His attention to language works in a similar way. Grammar studies the conventions of a particular language, while logic studies forms of reasoning that aspire to universality. A philosopher working in Arabic had to understand both. Technical concepts need linguistic bodies, and public teaching needs forms that audiences can receive. Al-Farabi therefore treats education as embodied and social. Human beings do not become rational by escaping language and music; they become rational through ordered uses of them.'
    ],['islamic-philosophy','epistemology','political-philosophy'],['al-farabi'],['Great Book of Music','Book of Letters']),
    section('influence-later','Influence on Avicenna, Maimonides, Averroes, and scholastic debates',[
      'Al-Farabi profoundly shaped the philosophical environment inherited by Avicenna. His work on logic, metaphysics, intellect, prophecy, and the classification of sciences provided problems and structures that Avicenna would transform into a more comprehensive system. Maimonides also inherited a world marked by Farabian themes, especially the relation between philosophy, law, prophecy, and political pedagogy. Averroes later disagreed with parts of the Avicennian and Farabian legacy while still working within a field they helped define.',
      'His influence is sometimes indirect because later systems became more famous. Yet many medieval debates about religion and philosophy are unintelligible without Farabian groundwork. The idea that religion can represent philosophical truth imaginatively, that logic ranks forms of assent, that political life aims at happiness, and that prophecy can be analyzed through intellect and imagination all remain active. Latin scholasticism did not simply receive Aristotle from Aristotle. It received Aristotle through Arabic projects that had already asked how reason, law, and happiness belong together.'
    ],['islamic-philosophy','logic','political-philosophy'],['al-farabi','avicenna','maimonides','averroes','aquinas'],['Enumeration of the Sciences','The Opinions of the People of the Virtuous City']),
    section('happiness-perfection','Happiness, perfection, and the philosophical life',[
      'Al-Farabi\'s political and metaphysical writings are ordered by the question of happiness. Happiness is not a mood, private satisfaction, or external success. It is the perfection proper to human beings as rational creatures. Because reason develops through education, virtue, and social cooperation, happiness cannot be secured by appetite or honor alone. The human good requires a city capable of directing desire toward what is truly complete.',
      'This view gives philosophy practical urgency. Logic, metaphysics, music, and politics are not separate hobbies for the learned. They contribute to forming persons who can know, desire, and act well. The highest life is intellectual, but it depends on habituation, language, law, and imagination. That dependence keeps al-Farabi from becoming merely individualistic. Even the philosopher needs a political and educational order that makes the pursuit of truth possible.'
    ],['political-philosophy','islamic-philosophy','epistemology'],['al-farabi','plato','aristotle'],['The Attainment of Happiness']),
    section('imperfect-cities','Imperfect cities and distorted ends',[
      'Al-Farabi\'s account of non-virtuous cities is as revealing as his ideal city. Communities can organize themselves around wealth, pleasure, domination, honor, freedom understood as license, or inherited opinion. These cities may be stable, impressive, or powerful, but their order reflects a mistaken account of the human good. Political failure begins when a community teaches its members to love a partial good as if it were final.',
      'This analysis remains philosophically useful even when one rejects the strict hierarchy of his ideal regime. It asks readers to diagnose public life by its organizing desire. What does a society reward? What does it train citizens to admire? What does it call success? Al-Farabi\'s answer is shaped by ancient and medieval assumptions, but the question travels well. Every political order contains an anthropology: an image of what human beings are for.'
    ],['political-philosophy','islamic-philosophy'],['al-farabi','plato'],['The Opinions of the People of the Virtuous City','The Political Regime']),
    section('misunderstandings-reading','Misunderstandings and a reading strategy',[
      'A common misunderstanding treats al-Farabi as a political utopian who merely Islamicizes Plato. Another treats him as a dry logician disconnected from religious life. Both miss the unity of his project. Logic matters because the city depends on forms of assent. Religion matters because truth must be represented for collective life. Politics matters because human happiness is not achieved by isolated minds alone. Metaphysics matters because happiness requires relation to the order of being.',
      'Begin with Enumeration of the Sciences to learn his map of knowledge, then read selections from the logical works to see how demonstration differs from dialectic, rhetoric, and poetry. Move next to The Opinions of the People of the Virtuous City and Book of Religion. Keep asking how each topic serves the formation of human beings toward happiness. Al-Farabi becomes clearer when read architectonically: each discipline has a place in a complete philosophical and political education.'
    ],['islamic-philosophy','logic','political-philosophy'],['al-farabi','plato','aristotle'],['Enumeration of the Sciences','The Opinions of the People of the Virtuous City','Book of Religion'])
  ],
  'al-ghazali':[
    section('overview','The critic who made philosophy answer for its claims',[
      'Al-Ghazali is often remembered as the great opponent of Islamic philosophy, especially because of The Incoherence of the Philosophers. That description is too simple. He was a jurist, theologian, logician, spiritual writer, educator, and critic who knew the philosophical tradition well enough to summarize it with force before attacking selected doctrines. His target was not reasoning as such. It was the claim that philosophers had demonstrated conclusions that, in his judgment, exceeded their proofs and threatened core religious commitments.',
      'His importance lies in the pressure he places on every intellectual path. Philosophers must show which claims are actually demonstrated. Theologians must learn disciplined reasoning rather than relying on slogans. Religious scholars must confront the condition of the soul, not only the correctness of outward forms. Mystical practice must be tested by law and doctrine. Al-Ghazali\'s work is therefore not a retreat from thought into piety. It is a demand that knowledge become truthful, limited, and transformative.'
    ],['islamic-philosophy','philosophy-of-religion','epistemology'],['al-ghazali','avicenna','averroes'],['The Incoherence of the Philosophers','Deliverance from Error']),
    section('life-crisis','Life, career, and intellectual crisis',[
      'Al-Ghazali was born in the eleventh century and became one of the leading scholars of the Seljuk-era Sunni world. His appointment at the Nizamiyya madrasa in Baghdad placed him at the center of religious and intellectual authority. He mastered law, theology, philosophy, logic, and debate, gaining prestige in a culture where public teaching and disputation mattered. Yet his own account presents this success as spiritually dangerous. The scholar can win arguments while losing sincerity.',
      'His crisis led him to leave his prestigious post and pursue a life of spiritual discipline, travel, and reflection before returning to teaching. The autobiographical work Deliverance from Error should be read carefully; it is a crafted intellectual and spiritual narrative, not a modern diary. Still, it shows the unity of his concerns. The problem is not only which doctrines are true, but what kind of person seeks them, why, and with what effect on the heart.'
    ],['philosophy-of-religion','epistemology'],['al-ghazali'],['Deliverance from Error']),
    section('philosophical-training','Knowing philosophy from the inside',[
      'Al-Ghazali\'s criticism of the philosophers depends on serious study. In The Doctrines of the Philosophers, he presents philosophical teachings with enough clarity that the work could be mistaken, especially in translation, for a neutral or even sympathetic exposition. This preparatory step matters. He argues that one cannot refute a view responsibly without first understanding it in its strongest form. Polemic without comprehension is intellectual dishonesty.',
      'The philosophers he targets are especially those shaped by al-Farabi and Avicenna. He distinguishes areas where philosophical work is relatively harmless or useful, such as mathematics and logic, from metaphysical claims he thinks are dangerous and inadequately demonstrated. This discriminating approach is often lost in simplified accounts. Al-Ghazali does not say every Greek-derived science is unbelief. He asks which conclusions follow by proof, which are conjectural, and which conflict with doctrines that religious communities cannot abandon.'
    ],['islamic-philosophy','epistemology','logic'],['al-ghazali','al-farabi','avicenna'],['The Doctrines of the Philosophers']),
    section('incoherence','The Incoherence and the limits of demonstration',[
      'The Incoherence of the Philosophers attacks twenty philosophical theses, with special concern for the eternity of the world, God\'s knowledge of particulars, and bodily resurrection. Al-Ghazali argues that the philosophers have not demonstrated these contested claims and that some of them contradict central religious teachings. The work is not a general attack on logic. It often uses careful argument, distinctions, and objections drawn from the philosophers\' own commitments.',
      'Its title is well chosen. The charge is incoherence: the philosophers claim demonstrative certainty but rely on assumptions, analogies, or necessities they have not proven. Al-Ghazali does not need to show that every alternative doctrine is demonstratively established by philosophy. He needs to show that the philosophers\' claim to decisive proof fails. The result is a powerful critique of intellectual overreach. Philosophy is not condemned for asking metaphysical questions; it is challenged for confusing system with demonstration.'
    ],['islamic-philosophy','philosophy-of-religion','epistemology'],['al-ghazali','avicenna','averroes'],['The Incoherence of the Philosophers']),
    section('causality','Causality, occasionalism, and the fire and cotton debate',[
      'Al-Ghazali is famous for arguing that the observed connection between what we call cause and effect does not by itself prove necessary connection. Fire usually burns cotton, but observation shows constant conjunction, not an independent necessity binding fire to burning apart from God\'s will. This argument serves a theological purpose: it protects divine power and the possibility of miracles against a view of nature as closed by necessity.',
      'The position is often called occasionalism, though interpreters debate how broadly that label should be applied to al-Ghazali. He does not deny that regular patterns exist in nature or that humans can rely on them in practice. The question is metaphysical: are created things independent necessitating causes, or do events depend at every moment on God\'s creative act? The subtlety matters. Al-Ghazali is not saying the world is chaotic. He is saying that order is contingent on divine governance rather than self-subsisting necessity.'
    ],['metaphysics','philosophy-of-religion','islamic-philosophy'],['al-ghazali','avicenna','averroes','aquinas'],['The Incoherence of the Philosophers']),
    section('knowledge-skepticism','Skepticism, certainty, and the search for secure knowledge',[
      'In Deliverance from Error, al-Ghazali describes a crisis over the reliability of sense perception and even rational judgments. Senses deceive, and rational principles might seem vulnerable if a higher faculty could expose them as dreams expose ordinary waking confidence. This skeptical moment is not the final position. It dramatizes the need for a kind of certainty that is not merely inherited from teachers or social authority.',
      'His resolution involves divine illumination, disciplined inquiry, and spiritual transformation. The precise interpretation is disputed: some readers emphasize a rational restoration, others a mystical light beyond argument. What should not be missed is that al-Ghazali takes epistemic responsibility seriously. He refuses blind imitation, but he also refuses the fantasy that human beings can secure truth by technique alone. Knowledge depends on method, moral condition, divine generosity, and recognition of the limits of each discipline.'
    ],['epistemology','philosophy-of-religion'],['al-ghazali','avicenna'],['Deliverance from Error']),
    section('logic-theology','Logic, theology, and disciplined religious reasoning',[
      'Al-Ghazali helped legitimate the use of logic in Islamic religious sciences. He argued that logical forms are tools for distinguishing valid from invalid inference and need not carry unacceptable metaphysical baggage. This was a major intervention. If logic is treated as foreign contamination, religious argument becomes weaker; if logic is treated as sufficient for all truth, philosophy becomes arrogant. Al-Ghazali tries to occupy a middle position.',
      'His theological work shows the same balance. Kalam needs rigor, but it also has limits. It can defend doctrine, answer opponents, and clarify belief, yet it may not heal the soul or bring the highest knowledge of God. This layered view of disciplines is one of al-Ghazali\'s deepest contributions. Different sciences have different purposes. Confusing their scopes leads either to anti-intellectualism or to misplaced confidence.'
    ],['logic','philosophy-of-religion','islamic-philosophy'],['al-ghazali','al-farabi','avicenna'],['The Just Balance']),
    section('sufism-ethics','Sufism, ethics, and the revival of religious life',[
      'The Revival of the Religious Sciences is al-Ghazali\'s great project of moral and spiritual reform. It treats worship, social practice, destructive vices, saving virtues, intention, repentance, patience, gratitude, love, and remembrance. The point is not to replace law with inward feeling. It is to show that outward correctness without inward transformation is incomplete. A person can perform religious actions while being governed by pride, envy, greed, or the desire for reputation.',
      'This ethical and spiritual focus belongs with his philosophical critique. The problem with intellectual life is not only false doctrine; it is also disordered desire. Scholars may seek victory rather than truth. Philosophers may seek prestige through subtlety. Devotees may seek admiration for piety. Al-Ghazali\'s mature project asks how knowledge becomes salvific rather than merely decorative. That question makes him relevant far beyond the medieval controversies in which he wrote.'
    ],['philosophy-of-religion','epistemology'],['al-ghazali'],['Revival of the Religious Sciences']),
    section('relation-avicenna','Relation to Avicenna and the falasifa',[
      'Al-Ghazali\'s most famous philosophical opponent is the Avicennian tradition. Avicenna had built a powerful system around essence and existence, necessary and possible being, emanation, intellect, and a philosophical account of prophecy. Al-Ghazali recognizes the system\'s power, which is why his critique matters. He does not attack a weak caricature. He challenges a form of philosophy that claimed to explain the world, God, soul, and religion through demonstrative reason.',
      'His relation to Avicenna is therefore more intimate than simple opposition. He borrows logical tools, studies philosophical classifications, and accepts some conclusions while rejecting others. In some areas, later Islamic thought becomes deeply post-Avicennian and post-Ghazalian at the same time. The tension between system and critique becomes productive. Al-Ghazali forces philosophers and theologians alike to ask whether metaphysical necessity has been proven, whether divine freedom has been protected, and whether intellectual knowledge changes the soul.'
    ],['islamic-philosophy','metaphysics','philosophy-of-religion'],['al-ghazali','avicenna','averroes'],['The Incoherence of the Philosophers','The Doctrines of the Philosophers']),
    section('averroes-response','Averroes and the counter-attack',[
      'Averroes answered al-Ghazali in The Incoherence of the Incoherence, defending philosophy and attacking what he saw as misunderstandings or theological overreaches. This later response is one reason al-Ghazali is sometimes cast as the destroyer of philosophy and Averroes as its rescuer. That drama is too theatrical. Philosophy continued in many Islamic contexts after al-Ghazali, and Averroes\' own influence was stronger in some Jewish and Latin settings than in many eastern Islamic circles.',
      'The exchange is still crucial. Al-Ghazali presses the philosophers on causality, eternity, divine knowledge, and resurrection; Averroes presses theologians on interpretation, demonstration, and the integrity of Aristotle. Together they clarify the stakes of medieval philosophy of religion. Does reason demonstrate a necessary cosmic order, or does it reveal its own limits before divine freedom? When scripture and demonstration appear to conflict, who has authority to interpret? The debate remains alive because both sides expose real weaknesses.'
    ],['islamic-philosophy','philosophy-of-religion','aristotelianism'],['al-ghazali','averroes','aristotle'],['The Incoherence of the Philosophers','Incoherence of the Incoherence']),
    section('divine-knowledge','Divine knowledge, particulars, and religious concern',[
      'One of al-Ghazali\'s sharpest objections concerns the claim that God knows particulars only in a universal way. He worries that such a doctrine empties divine knowledge of concrete providential care and makes God too remote from the changing lives of creatures. The issue is not a small technicality. It touches prayer, judgment, moral accountability, and the trust that God knows what happens to individual persons.',
      'The philosophers were trying to protect divine immutability and simplicity: if God changes by acquiring new information, God seems dependent on the world. Al-Ghazali argues that this philosophical solution creates a worse religious problem. The debate shows his method at its strongest. He identifies the pressure that produced the philosophers\' doctrine, then asks whether the doctrine can survive the full demands of monotheistic worship, providence, and scriptural teaching.'
    ],['philosophy-of-religion','metaphysics','islamic-philosophy'],['al-ghazali','avicenna','averroes'],['The Incoherence of the Philosophers']),
    section('niche-of-lights','Light, symbolism, and the language of spiritual ascent',[
      'The Niche of Lights shows a different but related side of al-Ghazali. There he interprets Qur\'anic light imagery through a hierarchy of perception, intellect, and divine illumination. The work uses philosophical vocabulary and mystical symbolism without reducing one to the other. Light becomes a way to speak about manifestation, dependence, knowledge, and the soul\'s movement from sensory appearances toward the source of intelligibility.',
      'This symbolic writing complicates the image of al-Ghazali as merely anti-philosophical. He can criticize metaphysical overreach in the falasifa while using refined philosophical psychology in a spiritual key. The question is always one of ordering. Concepts, images, and practices must lead the soul toward God rather than toward pride in system-building. The Niche of Lights therefore belongs beside the Incoherence and the Revival: critique, symbolism, and ethical transformation are parts of one project.'
    ],['philosophy-of-religion','epistemology','islamic-philosophy'],['al-ghazali','avicenna'],['The Niche of Lights']),
    section('misunderstandings','Common misunderstandings and interpretive tensions',[
      'The most common misunderstanding is that al-Ghazali ended philosophy in the Islamic world. This is historically misleading. Philosophical theology, logic, Avicennian metaphysics, illuminationist thought, and later traditions continued in varied forms. Al-Ghazali changed the terms of debate by making philosophers answer harder questions, but he did not make reasoning disappear. Another misunderstanding is that he rejected causality in the practical sense. He challenged necessary causal power in created things, not the reliability of ordinary patterns as habits of divine action.',
      'Interpretive tensions remain. How skeptical is he in Deliverance from Error? How occasionalist is his metaphysics? Does his critique of the philosophers depend on theological commitments that philosophy itself need not grant? Does his spiritual project correct or overshadow his dialectical work? These questions should be kept open. Al-Ghazali is powerful because he resists easy classification as philosopher, anti-philosopher, theologian, mystic, or jurist. He is all of these in a contested arrangement.'
    ],['islamic-philosophy','epistemology','philosophy-of-religion'],['al-ghazali','avicenna','averroes'],['Deliverance from Error','The Incoherence of the Philosophers']),
    section('reading-strategy','How to read al-Ghazali without the legend',[
      'A good reading path begins with Deliverance from Error, not because it is a simple autobiography, but because it introduces the problem of certainty, imitation, and spiritual sincerity. Then read The Doctrines of the Philosophers before The Incoherence of the Philosophers, so the critique appears as a response to a position he has first reconstructed. Add selected books from the Revival of the Religious Sciences to see why the purification of the soul belongs to his theory of knowledge.',
      'Read slowly around the question of scope. When al-Ghazali criticizes philosophers, ask which philosophers, which claims, and which standard of proof are in view. When he praises Sufi practice, ask how it relates to law, theology, and reason. When he uses logic, ask why he thinks a foreign-origin tool can serve religious truth. This strategy prevents the flat legend of destruction and reveals a thinker trying to discipline every claim to knowledge, including his own tradition\'s.'
    ],['islamic-philosophy','philosophy-of-religion','epistemology'],['al-ghazali','avicenna','averroes'],['Deliverance from Error','The Doctrines of the Philosophers','The Incoherence of the Philosophers','Revival of the Religious Sciences'])
  ],
  averroes:[
    section('overview','The commentator who defended philosophy as a religious duty',[
      'Averroes, or Ibn Rushd, is one of the most important Aristotelian philosophers of the medieval world. He was a jurist, physician, judge, commentator, and philosopher in twelfth-century al-Andalus and North Africa. His reputation in Latin Europe rested above all on his commentaries on Aristotle, so much so that he became known simply as "the Commentator." Yet that title can hide the boldness of his project. Averroes did not merely explain Aristotle. He defended philosophical demonstration as a legitimate and, for qualified people, obligatory path to truth.',
      'His work belongs to several conversations at once. He responds to al-Ghazali\'s critique of the philosophers, resists Avicennian departures from Aristotle, interprets scripture in relation to demonstration, and develops positions on intellect, law, medicine, politics, and metaphysics that shaped Jewish and Christian scholasticism. He is best approached as a philosopher of disciplined hierarchy: kinds of people, kinds of argument, kinds of texts, and kinds of certainty must be distinguished if reason and revelation are to avoid destructive confusion.'
    ],['islamic-philosophy','aristotelianism','philosophy-of-religion'],['averroes','aristotle','al-ghazali','aquinas'],['Decisive Treatise','Incoherence of the Incoherence']),
    section('andalus-context','Al-Andalus, law, medicine, and courtly politics',[
      'Averroes was born in Cordoba in 1126 into a family of jurists. He served as a judge and physician and worked under Almohad patronage, a setting that could support philosophy but also expose it to political and religious vulnerability. Al-Andalus was a crossroads of Islamic law, Arabic philosophy, medicine, poetry, Jewish thought, and contact with Latin Christendom. Averroes\' career shows that philosophy was not isolated from institutions. It moved through courts, legal offices, libraries, medical practice, and controversies over public teaching.',
      'His later difficulties, including a period of disgrace, remind readers that the defense of philosophy had stakes. A philosopher who is also a jurist cannot treat interpretation as a private amusement. Claims about who may interpret scripture, how demonstration relates to law, and whether philosophers should speak publicly affect communal order. Averroes writes from within Islamic legal and political life, not outside it. That is why his philosophical confidence is paired with caution about audience and method.'
    ],['islamic-philosophy','political-philosophy','philosophy-of-religion'],['averroes','maimonides'],[]),
    section('commentary-project','The commentary project and the recovery of Aristotle',[
      'Averroes wrote short, middle, and long commentaries on many works of Aristotle. The different formats served different readers and purposes, from paraphrase to detailed line-by-line analysis. His goal was not antiquarian preservation. He believed Aristotle had reached the highest available scientific understanding in many fields, and that later interpreters often obscured Aristotle by mixing him with Neoplatonic or Avicennian ideas. Commentary became a philosophical method for restoring demonstration.',
      'This project shaped Latin scholasticism profoundly. Translated commentaries helped European readers encounter Aristotle as a systematic authority in logic, natural philosophy, psychology, metaphysics, ethics, and politics. Yet Averroes should not be reduced to a servant of Latin Aristotle. His commentaries are interventions in Arabic philosophy as well, especially against readings he considered insufficiently Aristotelian. The commentator is an original thinker precisely because he decides what faithful interpretation requires.'
    ],['aristotelianism','logic','islamic-philosophy'],['averroes','aristotle','avicenna','aquinas'],['Long Commentary on the Metaphysics','Long Commentary on De Anima']),
    section('decisive-treatise','The Decisive Treatise and the legal case for philosophy',[
      'The Decisive Treatise argues that the study of philosophy is required for those capable of demonstrative reasoning because revelation commands reflection on beings as signs of the Creator. The argument is striking: philosophy is not defended as a harmless foreign pastime but as a religiously mandated inquiry when pursued by qualified minds. Demonstration studies created reality in order to know its maker more fully.',
      'Averroes also insists that apparent conflict between demonstrative truth and scripture must be handled through interpretation. Since truth cannot contradict truth, a demonstrated conclusion may require nonliteral reading of a scriptural passage. But this permission is not given to everyone in every setting. Different audiences require different forms of teaching. The result is a powerful and controversial theory: philosophy and revelation agree in truth, but public confusion arises when modes of discourse are mixed without discipline.'
    ],['philosophy-of-religion','islamic-philosophy','epistemology'],['averroes','aristotle','al-ghazali'],['Decisive Treatise']),
    section('demonstration-audience','Demonstration, dialectic, rhetoric, and audience',[
      'Averroes inherits the Aristotelian distinction among demonstrative, dialectical, and rhetorical reasoning and gives it religious significance. Demonstration yields scientific certainty for those trained in the relevant methods. Dialectic works through accepted opinions and is useful for debate. Rhetoric persuades broader audiences through accessible arguments and images. These are not equally precise, but each has a public role.',
      'The danger comes when rhetorical believers are exposed to difficult interpretations without preparation, or when dialectical theologians mistake non-demonstrative arguments for certainty. Averroes thinks much conflict arises from such category mistakes. This view can sound elitist because it restricts interpretation to trained demonstrators. It can also sound humane because it recognizes that teaching must fit capacities. The philosophical issue is whether protecting audiences preserves truth or gives intellectual elites too much authority over meaning.'
    ],['epistemology','logic','philosophy-of-religion'],['averroes','al-farabi','aristotle'],['Decisive Treatise']),
    section('ghazali-response','Answering al-Ghazali in the Incoherence of the Incoherence',[
      'Averroes wrote The Incoherence of the Incoherence as a response to al-Ghazali\'s attack on the philosophers. He defends causal order, the eternity or everlasting dependence of the world as he understands Aristotle, and the legitimacy of philosophical interpretation. He often argues that al-Ghazali has misunderstood the philosophers or has relied on theological assumptions that do not defeat demonstration. The exchange is one of the central monuments of medieval philosophy of religion.',
      'Averroes\' response is not merely defensive. He also criticizes Avicennian positions when he thinks al-Ghazali has attacked a version of philosophy already corrupted by non-Aristotelian additions. This makes the debate triangular: Aristotle, Avicenna, and al-Ghazali all stand in the background. Averroes wants to defend philosophy by returning it to Aristotle, not by accepting every claim made by earlier Islamic philosophers. His anti-Ghazalian work is therefore also an anti-Avicennian purification.'
    ],['islamic-philosophy','aristotelianism','metaphysics'],['averroes','al-ghazali','avicenna','aristotle'],['Incoherence of the Incoherence','The Incoherence of the Philosophers']),
    section('metaphysics-cosmos','Metaphysics, eternity, and divine causality',[
      'Averroes\' metaphysics is deeply Aristotelian. He resists accounts that make the world a temporal artifact produced after absolute nonbeing in a way he thinks conflicts with philosophical demonstration. For him, divine causality is not a changeable act in time but the eternal dependence of the ordered cosmos on the first principle. This does not mean God is absent. It means divine causality is understood through intelligible order, motion, final causality, and the dependence of all beings on the highest cause.',
      'This position generated intense controversy. Theologians worried that an eternal world threatened divine freedom and creation. Averroes worried that crude temporal images of creation made God too much like a craftsman undergoing change. The disagreement depends on what counts as preserving divine transcendence. Is God more exalted if the world begins by will after not existing, or if the whole order eternally depends on God without change in God? Averroes chooses the latter philosophical route, while insisting that properly interpreted revelation does not contradict truth.'
    ],['metaphysics','philosophy-of-religion','aristotelianism'],['averroes','aristotle','al-ghazali','aquinas'],['Long Commentary on the Metaphysics','Incoherence of the Incoherence']),
    section('intellect','The intellect and the controversy over human understanding',[
      'Averroes\' theory of intellect became one of the most controversial parts of his legacy. In interpreting Aristotle\'s De Anima, he argued in ways that Latin readers associated with a shared or separate material intellect rather than a fully individual intellectual power for each human being. The details are complex and developed across his writings, but the central problem is clear: how can universal intelligible knowledge be received by embodied individuals whose images and experiences are particular?',
      'Latin scholastics, including Aquinas, attacked what they took to be Averroism because it seemed to threaten personal immortality, individual responsibility, and the unity of the human person. Averroes himself was trying to solve Aristotelian problems about abstraction, intelligibility, and the relation between imagination and intellect. The controversy shows how technical psychology can become theological and political. A theory of how humans understand can alter doctrines of soul, salvation, education, and moral agency.'
    ],['epistemology','aristotelianism','metaphysics'],['averroes','aristotle','aquinas'],['Long Commentary on De Anima']),
    section('law-politics',"Law, political order, and Plato's Republic",[
      'Averroes wrote a commentary or paraphrase on Plato\'s Republic, known largely through Hebrew and Latin transmission. Like al-Farabi, he was interested in the relation between philosophy, law, education, and the best regime. But Averroes\' political thought is shaped by his role as a jurist and by his concern that revealed law guides communities through different levels of understanding. Law is not merely coercive rule; it is an educational structure that orders beliefs and actions toward human perfection.',
      'His political reflections also include sharp judgments about defective regimes, honor, wealth, tyranny, and the education of rulers. Modern readers should be cautious because the transmitted text and its relation to Plato are complex. Still, Averroes\' interest in the Republic confirms that his Aristotelianism was not narrow. He saw political order as a condition for the flourishing of rational and moral life. Philosophy needs institutions, and institutions need ordered accounts of the human good.'
    ],['political-philosophy','islamic-philosophy','aristotelianism'],['averroes','plato','al-farabi'],["Commentary on Plato's Republic"]),
    section('medicine-science','Medicine, natural philosophy, and embodied knowledge',[
      'Averroes was also a physician and wrote the Colliget, a general medical work. His medical activity belongs with his broader Aristotelian commitment to studying nature through ordered causes. Human beings are embodied animals as well as rational knowers, and the health of the body matters for the conditions of inquiry and civic life. Medicine, natural philosophy, and psychology are not isolated compartments.',
      'This scientific side complicates the image of Averroes as only a commentator on metaphysics. He worked in a world where philosophy included the study of living bodies, perception, generation, celestial motion, and the practical arts of healing. Some scientific claims belong to their historical context and cannot be accepted uncritically today. But the intellectual posture remains important: reason honors creation by studying its order in detail, not by leaping immediately to abstract theology.'
    ],['islamic-philosophy','aristotelianism','epistemology'],['averroes'],['Colliget']),
    section('latin-legacy','Latin Averroism, Jewish reception, and Aquinas',[
      'Averroes\' influence in Latin Europe was immense. His commentaries helped universities read Aristotle, and debates over intellect, eternity, providence, and the relation between philosophy and theology often passed through Averroist or anti-Averroist forms. Aquinas learned from Averroes even while criticizing him sharply, especially on the unity of the intellect and the eternity of the world. This is a good example of influence through disagreement: an opponent can shape the questions one must answer.',
      'Jewish philosophers also engaged Averroes, often through Hebrew translations and commentaries. His impact varied across regions and traditions. In some Islamic contexts his legacy was less institutionally dominant than in Latin scholasticism, while in Europe he became a symbol of radical Aristotelian philosophy. That symbolic Averroes was sometimes more extreme than the historical Ibn Rushd. Reading reception carefully means distinguishing the Andalusian jurist-philosopher from later "Averroism" as a contested label.'
    ],['aristotelianism','islamic-philosophy','philosophy-of-religion'],['averroes','aquinas','maimonides','aristotle'],['Long Commentary on De Anima','Long Commentary on the Metaphysics']),
    section('scripture-interpretation','Scripture, interpretation, and the danger of public confusion',[
      'Averroes\' theory of interpretation depends on the conviction that scripture addresses all people while demonstration is available only to some. Scriptural language therefore includes apparent meanings, images, and exhortations fitted to moral and communal guidance. When a demonstrative conclusion conflicts with an apparent meaning, trained interpreters may seek a deeper reading. But they must not scatter difficult interpretations among audiences for whom they would produce confusion rather than understanding.',
      'This position is both subtle and risky. It preserves the unity of truth while recognizing different capacities, but it can also make philosophical elites gatekeepers of meaning. Averroes would answer that public teaching without order damages both religion and philosophy. Modern readers may press the political problem harder: who decides who is qualified, and how can authority be corrected? The tension belongs to the heart of his project, not its margins.'
    ],['philosophy-of-religion','epistemology','political-philosophy'],['averroes','al-farabi','maimonides'],['Decisive Treatise']),
    section('misunderstandings','Common misunderstandings and interpretive tensions',[
      'One misunderstanding treats Averroes as a secular rationalist opposed to religion. The Decisive Treatise shows something more complicated: he defends philosophy through Islamic legal reasoning and insists that demonstrated truth and revelation cannot genuinely conflict. Another misunderstanding treats him as merely a commentator with no original thought. His originality appears in what he thinks commentary is for, how he ranks methods, how he reads Aristotle against rivals, and how he connects interpretation to law.',
      'Real tensions remain. His audience hierarchy can look protective or authoritarian. His theory of intellect can seem to endanger individual immortality. His account of eternity can appear difficult to reconcile with ordinary creation doctrine. His confidence in Aristotle can look excessive after modern science. These tensions should not be smoothed away. Averroes matters because he makes a demanding wager: that disciplined demonstration, properly interpreted revelation, and ordered political teaching can form one truth without collapsing into confusion.'
    ],['islamic-philosophy','aristotelianism','philosophy-of-religion'],['averroes','al-ghazali','aquinas'],['Decisive Treatise','Incoherence of the Incoherence']),
    section('reading-strategy','How to read Averroes as more than a legend',[
      'Begin with the Decisive Treatise to understand why Averroes thinks philosophy can be a religious obligation for qualified inquirers. Then read selections from the Incoherence of the Incoherence beside al-Ghazali, so the debate does not collapse into slogans. Add a commentary on Aristotle, especially De Anima or Metaphysics, to see how his method works in detail. Finally examine his reception in Aquinas or Latin debates to see how interpretation can transform a thinker into a symbol.',
      'The central reading discipline is to track audiences and methods. Is Averroes speaking demonstratively, dialectically, juridically, or pedagogically? Is he defending Aristotle, correcting Avicenna, answering al-Ghazali, or explaining scripture? Many apparent contradictions become clearer when the genre and audience are identified. Even then, difficult questions remain. Averroes rewards readers who can keep legal, philosophical, religious, and scientific contexts in view at the same time.'
    ],['islamic-philosophy','aristotelianism','epistemology'],['averroes','al-ghazali','aristotle','aquinas'],['Decisive Treatise','Incoherence of the Incoherence','Long Commentary on De Anima'])
  ]
};
